def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 1:
            priorities[i] = float('inf')
            continue
        score = 0
        for j in range(1, 7):
            if j % 2 == 0:
                term = (ratio ** j) / (j + 1)
            else:
                term = ((1 - ratio) ** j) / (j + 2)
            if j % 3 == 0:
                term *= np.log1p(cap + j)
            else:
                term *= np.sqrt(cap) / (j + 1)
            score += term
        if cap < item * 1.5:
            score *= (1 + 0.5 * np.sin(cap))
        elif cap > item * 4:
            score *= (0.7 + 0.3 * np.cos(cap))
        if i % 3 == 0:
            for k in range(1, 4):
                if (cap + k) % 2 == 0:
                    score += k / (cap + k)
                else:
                    score -= k * ratio / (cap + k + 1)
        priorities[i] = 1 / (score + 1e-5)
    return priorities
